129	/// Run the `bot-session` subcommand: parse the transcript and
130	/// print the conversation view plus the trailing summary line.
131	///
132	/// `ctx` is unused — bot-session reads a plain file; it's present
133	/// for the uniform subcommand-layer signature.
134	pub fn bot_session(
135	    _ctx: &Context,
136	    params: &BotSessionParams,
137	) -> Result<(), Box<dyn std::error::Error>> {
138	    debug!("bot-session: enter");
139	    let t = transcript::parse_file(&params.file)?;
140	    for (line_no, err) in &t.malformed {
141	        warn!("bot-session: line {line_no}: {err}");
142	    }
143	    let (lines, stats) = render(&t, &params.opts);
144	    let lines = match &params.lines {
145	        Some(spec) => apply_lines(lines, spec),
146	        None => lines,
147	    };
148	    for line in &lines {
149	        info!("{line}");
150	    }
151	    info!("");
152	    info!("{}", summary_line(&stats, t.malformed.len()));
153	    debug!("bot-session: exit");
154	    Ok(())
155	}
