1	//! User-level config loaded from `~/.config/vc-x1/config.toml`.
2	//!
3	//! Backs init's account/repo-target resolution. No magic
4	//! fallbacks — a missing file or missing key produces a
5	//! predictable error pointing at the exact key to set.
6	//!
7	//! Schema (multi-account, dotted keys for compactness):
8	//!
9	//! ```toml
10	//! [default]
11	//! account = "home"      # default --account when absent
12	//! debug   = "trace"     # default --debug value when used without arg
13	//!
14	//! [account.home]
15	//! repo.default          = "remote"                       # default --repo cat when absent
16	//! repo.category.remote  = "git@github.com:winksaville"   # value for --repo remote (no =val)
17	//! repo.category.local   = "~/test-fixtures"              # value for --repo local (no =val)
18	//!
19	//! [account.work]
20	//! repo.default          = "remote"
21	//! repo.category.remote  = "git@github.com:anthropic"
22	//! repo.category.local   = "/work/fixtures"
23	//! ```
24	//!
25	//! Three-layer resolution — see
26	//! `notes/chores/chores-08.md > User config (0.41.1-3, redesigned in 0.41.1-4)`:
27	//!
28	//! 1. account: CLI `--account` → `[default].account` → error.
29	//! 2. category: CLI `--repo <cat>` → `[account.<a>.repo].default`
30	//!    → error.
31	//! 3. value: CLI `--repo <cat>=<val>` →
32	//!    `[account.<a>.repo.category].<cat>` → error.
33	//!
34	//! Values are **literal targets**, not section-name pointers.
35	//! For built-in `category = "remote"` the value is a URL prefix
36	//! (init appends `/<NAME>.git`); for `category = "local"` it's
37	//! the parent dir for fixture bare repos.
38	//!
39	//! `-3` shipped a flat first-cut (`[default] repo-remote-provider`,
40	//! `[github] owner`); `-4` is the redesign before any consumer
41	//! is wired in. `-5` (init reshape) is the first consumer.
42	
43	use std::collections::HashMap;
44	use std::path::{Path, PathBuf};
45	
46	use log::debug;
47	
48	use crate::toml_simple;
49	
50	/// Per-account configuration.
51	///
52	/// - `repo_default` — `[account.<name>.repo].default` — the
53	///   category to use when `--repo` is absent.
54	/// - `repo_category` — `[account.<name>.repo.category]` — map
55	///   from category name (e.g. `"remote"`, `"local"`) to its
56	///   literal value (URL prefix, fixture parent dir, etc.).
57	#[derive(Debug, Default, Clone, PartialEq, Eq)]
58	pub struct AccountConfig {
59	    pub repo_default: Option<String>,
60	    pub repo_category: HashMap<String, String>,
61	}
62	
63	/// Resolved user config.
64	///
65	/// All fields are optional or default-empty — absent file or
66	/// absent keys yield empty values. Consumers apply their own
67	/// errors at use time.
68	///
69	/// **Two write modes** for repo defaults:
70	/// - **Top-level `[repo]`** — single-account shorthand. Sits in
71	///   `top_level_repo`. Used when neither `--account` nor
72	///   `[default].account` resolves to a known account.
73	/// - **`[account.<name>]`** — multi-account. Sits in `accounts`.
74	///   Selected by `--account` CLI or `[default].account`.
75	///
76	/// Mixing both is rejected at load time (ambiguous which one
77	/// init should consult).
78	#[derive(Debug, Default, Clone, PartialEq, Eq)]
79	pub struct UserConfig {
80	    /// `[default].account` — default account when `--account`
81	    /// is absent.
82	    pub default_account: Option<String>,
83	
84	    /// `[default].debug` — default value when `--debug` is used
85	    /// without an argument. (Reserved; not currently consumed.)
86	    pub default_debug: Option<String>,
87	
88	    /// Top-level `[repo]` — single-account shorthand. `Some`
89	    /// only when the file has top-level `repo.*` keys and no
90	    /// `[account.*]` sections.
91	    pub top_level_repo: Option<AccountConfig>,
92	
93	    /// Per-account configuration, keyed by account name.
94	    pub accounts: HashMap<String, AccountConfig>,
95	}
96	
97	/// CLI selector for `--repo <cat>[=<val>]`.
98	///
99	/// - `--repo` absent → `None`.
100	/// - `--repo <cat>` → `Some({ category: cat, value: None })`.
101	/// - `--repo <cat>=<val>` → `Some({ category: cat, value: Some(val) })`.
102	#[derive(Debug, Clone, PartialEq, Eq)]
103	pub struct RepoSelector {
104	    pub category: String,
105	    pub value: Option<String>,
106	}
107	
108	/// Path to the user config file.
109	///
110	/// - Honors `$XDG_CONFIG_HOME` if set (XDG Base Directory spec).
111	/// - Falls back to `$HOME/.config`.
112	/// - Errors if neither variable is set.
113	pub fn config_path() -> Result<PathBuf, Box<dyn std::error::Error>> {
114	    let base = if let Some(xdg) = std::env::var_os("XDG_CONFIG_HOME") {
115	        PathBuf::from(xdg)
116	    } else if let Some(home) = std::env::var_os("HOME") {
117	        PathBuf::from(home).join(".config")
118	    } else {
119	        return Err("neither $XDG_CONFIG_HOME nor $HOME is set".into());
120	    };
121	    Ok(base.join("vc-x1").join("config.toml"))
122	}
123	
124	/// Load the user config from the default location.
125	///
126	/// - Missing file → empty `UserConfig`.
127	/// - Malformed file → fatal error.
128	pub fn load() -> Result<UserConfig, Box<dyn std::error::Error>> {
129	    load_from(&config_path()?)
130	}
131	
132	/// Load the user config from an explicit path.
133	///
134	/// - Missing file → empty `UserConfig`.
135	/// - Malformed file → fatal error (propagated from `toml_simple`).
136	/// - Unknown sections / keys are silently ignored
137	///   (forward-compatible with future schema additions).
138	pub fn load_from(path: &Path) -> Result<UserConfig, Box<dyn std::error::Error>> {
139	    if !path.exists() {
140	        debug!(
141	            "config: file not found at {} — using empty UserConfig",
142	            path.display()
143	        );
144	        return Ok(UserConfig::default());
145	    }
146	    debug!("config: loading from {}", path.display());
147	    let map = toml_simple::toml_load(path)?;
148	
149	    let mut cfg = UserConfig {
150	        default_account: map.get("default.account").cloned(),
151	        default_debug: map.get("default.debug").cloned(),
152	        top_level_repo: None,
153	        accounts: HashMap::new(),
154	    };
155	
156	    let mut top_level = AccountConfig::default();
157	    let mut top_level_seen = false;
158	
159	    // Walk all keys; route `repo.*` to top-level, `account.<n>.…`
160	    // to per-account.
161	    for (full_key, value) in &map {
162	        if let Some(suffix) = full_key.strip_prefix("repo.") {
163	            top_level_seen = true;
164	            apply_repo_subkey(&mut top_level, suffix, value);
165	            continue;
166	        }
167	        let Some(rest) = full_key.strip_prefix("account.") else {
168	            continue;
169	        };
170	        let Some((name, suffix)) = rest.split_once('.') else {
171	            continue;
172	        };
173	        let Some(repo_suffix) = suffix.strip_prefix("repo.") else {
174	            continue; // unknown sub-section under [account.<n>]
175	        };
176	        let account = cfg.accounts.entry(name.to_string()).or_default();
177	        apply_repo_subkey(account, repo_suffix, value);
178	    }
179	
180	    if top_level_seen && !cfg.accounts.is_empty() {
181	        return Err(format!(
182	            "{}: mixing top-level [repo] with [account.*] is ambiguous — \
183	             remove top-level [repo] or move it under [account.<name>]",
184	            path.display()
185	        )
186	        .into());
187	    }
188	    if top_level_seen {
189	        cfg.top_level_repo = Some(top_level);
190	    }
191	
192	    debug!(
193	        "config: parsed default_account={:?}, default_debug={:?}, top_level_repo={}, accounts={:?}",
194	        cfg.default_account,
195	        cfg.default_debug,
196	        cfg.top_level_repo.is_some(),
197	        cfg.accounts.keys().collect::<Vec<_>>(),
198	    );
199	    Ok(cfg)
200	}
