202	/// Apply one `repo.*` sub-key (e.g. `default`, `category.remote`)
203	/// onto an `AccountConfig`. Used for both the top-level `[repo]`
204	/// path and the `[account.<n>.repo]` path.
205	fn apply_repo_subkey(account: &mut AccountConfig, suffix: &str, value: &str) {
206	    match suffix {
207	        "default" => {
208	            account.repo_default = Some(value.to_string());
209	        }
210	        s if let Some(cat) = s.strip_prefix("category.") => {
211	            account
212	                .repo_category
213	                .insert(cat.to_string(), value.to_string());
214	        }
215	        _ => {} // unknown sub-key; ignore (forward-compat)
216	    }
217	}
