219	/// Resolve `(category, value)` for an init invocation.
220	///
221	/// Three-step chain — each step has its own error message
222	/// pointing at the exact config key to set or CLI arg to pass.
223	///
224	/// - `account_override` — `Some(a)` from `--account a` CLI;
225	///   `None` falls back to `[default].account`.
226	/// - `repo_cli` — the parsed `--repo` selector (or `None` if
227	///   the flag was absent).
228	///
229	/// Fast path: when `repo_cli` provides both `category` and
230	/// `value` (`--repo <cat>=<val>`), the result is fully
231	/// determined by the CLI; no account or category lookup is
232	/// needed and account-related errors are skipped. This makes
233	/// config-less invocations (and test fixtures) work without a
234	/// `~/.config/vc-x1/config.toml`.
235	pub fn resolve_repo(
236	    cfg: &UserConfig,
237	    account_override: Option<&str>,
238	    repo_cli: Option<&RepoSelector>,
239	) -> Result<(String, String), Box<dyn std::error::Error>> {
240	    // Fast path: `--repo <cat>=<val>` is fully self-contained.
241	    if let Some(sel) = repo_cli
242	        && let Some(val) = sel.value.as_ref()
243	    {
244	        debug!(
245	            "resolve_repo: short-circuit — explicit cat={} val={} (from --repo CLI)",
246	            sel.category, val
247	        );
248	        return Ok((sel.category.clone(), val.clone()));
249	    }
250	
251	    // Step 1: pick the AccountConfig to use.
252	    //
253	    // - `--account` CLI → must hit `cfg.accounts[name]`.
254	    // - `[default].account` → must hit `cfg.accounts[that]`.
255	    // - Otherwise fall back to top-level `[repo]` (no account).
256	    // - Otherwise error.
257	    //
258	    // `account_label` is for error messages — section-name "<name>"
259	    // when an account was selected, "<top-level>" for the no-account
260	    // shorthand path.
261	    let (account, account_label, account_source) = match (account_override, &cfg.default_account) {
262	        (Some(name), _) => {
263	            let acct = cfg.accounts.get(name).ok_or_else(|| {
264	                format!("account '{name}' not found in config (no [account.{name}] section)")
265	            })?;
266	            (acct, name.to_string(), "--account CLI")
267	        }
268	        (None, Some(name)) => {
269	            let acct = cfg.accounts.get(name).ok_or_else(|| {
270	                format!(
271	                    "account '{name}' (from [default].account) not found in config \
272	                     (no [account.{name}] section)"
273	                )
274	            })?;
275	            (acct, name.clone(), "[default].account")
276	        }
277	        (None, None) => match cfg.top_level_repo.as_ref() {
278	            Some(r) => (r, String::from("<top-level>"), "top-level [repo]"),
279	            None => {
280	                return Err("no account specified; set [default].account, use \
281	                     --account <name>, or write a top-level [repo] section"
282	                    .into());
283	            }
284	        },
285	    };
286	    debug!(
287	        "resolve_repo: account = {} (from {})",
288	        account_label, account_source
289	    );
290	
291	    // Step 2: category.
292	    let (category, category_source) = match repo_cli {
293	        Some(sel) => (sel.category.clone(), "--repo CLI".to_string()),
294	        None => {
295	            let cat = account.repo_default.clone().ok_or_else(|| {
296	                section_error(
297	                    &account_label,
298	                    "no default category",
299	                    "repo",
300	                    "default",
301	                    "use --repo <cat>",
302	                )
303	            })?;
304	            (cat, format!("[account.{account_label}.repo].default"))
305	        }
306	    };
307	    debug!(
308	        "resolve_repo: category = {} (from {})",
309	        category, category_source
310	    );
311	
312	    // Step 3: value.
313	    let (value, value_source) = match repo_cli.and_then(|s| s.value.clone()) {
314	        Some(v) => (v, "--repo CLI value".to_string()),
315	        None => {
316	            let v = account
317	                .repo_category
318	                .get(&category)
319	                .cloned()
320	                .ok_or_else(|| {
321	                    section_error(
322	                        &account_label,
323	                        &format!("no value for --repo {category}"),
324	                        "repo.category",
325	                        &category,
326	                        &format!("--repo {category}=<val>"),
327	                    )
328	                })?;
329	            (
330	                v,
331	                format!("[account.{account_label}.repo.category].{category}"),
332	            )
333	        }
334	    };
335	    debug!("resolve_repo: value = {} (from {})", value, value_source);
336	
337	    Ok((category, value))
338	}
