340	/// Compose an error message for a missing-key case in `resolve_repo`.
341	///
342	/// Renders as `[account.<label>.<section_subpath>].<leaf>` for
343	/// named accounts and `[<section_subpath>].<leaf>` for the
344	/// top-level `[repo]` shorthand.
345	fn section_error(
346	    account_label: &str,
347	    msg: &str,
348	    section_subpath: &str,
349	    leaf: &str,
350	    cli_alt: &str,
351	) -> String {
352	    let section = if account_label == "<top-level>" {
353	        format!("[{section_subpath}]")
354	    } else {
355	        format!("[account.{account_label}.{section_subpath}]")
356	    };
357	    format!("{msg}; set {section}.{leaf} or use {cli_alt}")
358	}
