361	mod tests {
362	    use super::*;
363	    use std::path::Path;
364	    use std::sync::atomic::{AtomicU64, Ordering};
365	    use std::time::{SystemTime, UNIX_EPOCH};
366	    use std::{fs, path::PathBuf};
367	
368	    use crate::test_tmp_root::{resolve_tmp_root, should_keep_tempdir};
369	
370	    /// Per-process counter so same-nanosecond tempdir collisions
371	    /// yield distinct paths when tests run in parallel.
372	    static COUNTER: AtomicU64 = AtomicU64::new(0);
373	
374	    /// RAII tempdir for `config` tests — sibling of `Fixture` /
375	    /// `FixturePor` / `CliFixture`, scaled to the much smaller
376	    /// "write a config.toml and parse it" use case. Replaces the
377	    /// pre-0.41.1-6.4 `cfg_tempdir(tag) -> PathBuf` helper, which
378	    /// had no `Drop` and leaked one dir per test invocation.
379	    ///
380	    /// Uses the shared `resolve_tmp_root` (`$VC_X1_TEST_TMPDIR` →
381	    /// `std::env::temp_dir()`) and honors `should_keep_tempdir()`
382	    /// (`$VC_X1_TEST_KEEP`) so the same env-var knobs control all
383	    /// fixture types uniformly.
384	    struct CfgTempDir {
385	        dir: PathBuf,
386	    }
387	
388	    impl CfgTempDir {
389	        fn new(tag: &str) -> Self {
390	            let ts = SystemTime::now()
391	                .duration_since(UNIX_EPOCH)
392	                .map(|d| d.as_nanos())
393	                .unwrap_or(0); // OK: clock error → 0 is harmless for unique tempdir naming
394	            let n = COUNTER.fetch_add(1, Ordering::SeqCst);
395	            let dir = resolve_tmp_root().join(format!("vc-x1-cfg-{tag}-{ts}-{n}"));
396	            fs::create_dir_all(&dir).expect("mkdir cfg tempdir");
397	            Self { dir }
398	        }
399	
400	        fn dir(&self) -> &Path {
401	            &self.dir
402	        }
403	    }
404	
405	    impl Drop for CfgTempDir {
406	        fn drop(&mut self) {
407	            if should_keep_tempdir() {
408	                eprintln!("VC_X1_TEST_KEEP set; preserving {}", self.dir.display());
409	            } else {
410	                let _ = fs::remove_dir_all(&self.dir);
411	            }
412	        }
413	    }
414	
415	    /// Write `contents` to `<dir>/config.toml`. Returns the
416	    /// `CfgTempDir` guard alongside the file path so callers can
417	    /// keep the guard alive for the test's scope.
418	    fn write_cfg(tag: &str, contents: &str) -> (CfgTempDir, PathBuf) {
419	        let cfg = CfgTempDir::new(tag);
420	        let path = cfg.dir().join("config.toml");
421	        fs::write(&path, contents).unwrap();
422	        (cfg, path)
423	    }
424	
425	    /// `Drop` removes the tempdir on success: keep the path
426	    /// outside the inner scope, drop the guard, and verify the
427	    /// directory is gone. Pins the leak fix that landed in
